var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`아하하...... 혹시 깜짝파티 같은 건가요?`,JPN:`あはは……もしかしてサプライズパーティーか何かですか？`,ENG:`Ah hah hah... Is this some sort of surprise party?`,TWN:`哈哈哈……這該不會是驚喜派對之類的吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`오랜만에 뵙네요, 사장님. 덕분에 소대원들과 안락한 직장 생활을 만끽하고 있어요.`,JPN:`お久しぶりですね、社長。おかげ様で小隊員たちとの快適なワーキングライフを満喫しています。`,ENG:`Long time, no see, Boss. Thanks to you, my squad members and I've been enjoying stable work life.`,TWN:`久疏問候了，老闆。多虧了您，我才能和小隊成員盡情地享受職場生活。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`그렇지만 종신계약이라니......`,JPN:`それにしても、終身契約だなんて……`,ENG:`A lifetime contract, though...`,TWN:`不過竟然是終身契約……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`언더 출신 신입 사원에게 너무 많은 걸 기대하시는 게 아닐까, 어깨가 무겁네요.`,JPN:`そこまで期待してくださるなんて、アンダー上がりの新入社員である私には、少々荷が重いですね。`,ENG:`I'm afraid you may be expecting too much from a new employee who just left the Underground scene.`,TWN:`您會不會對出身底層的新員工抱有太高的期待了，感覺責任好重大呀。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`사람을 너무 쉽게 믿는 건 나쁜 버릇 아닐까 싶은데요.`,JPN:`人を簡単に信じすぎるのは、良くない傾向だと思いますよ。`,ENG:`You shouldn't be so trusting, either.`,TWN:`太過輕易地相信別人不是個好習慣。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`후후, 그렇지만 사장님과는 지금보다 조금 더 가깝게 지내도 괜찮을 것 같아요.`,JPN:`ふふ、でも、社長とはこれまで以上に親しくお付き合いさせていただきたいです。`,ENG:`Hah hah. But I wouldn't mind getting to know you better.`,TWN:`呵呵，不過和老闆稍微更親近一些，應該也沒關係。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`아, 물론 상사와 직원 사이의 적당한 거리감은 지키면서요. 폐가 되지 않게.`,JPN:`あっ、もちろん上司と部下なんですから、適切な距離感は保ちつつです。ご迷惑はおかけしません。`,ENG:`As a boss and his employee, of course.`,TWN:`啊，當然，我還是會保持老闆和員工之間的適當距離，不會給您添麻煩的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};